import { Alchemy, Network } from 'alchemy-sdk';
import { useEffect, useState } from 'react';
import "./blockStyles.css";

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};


// In this week's lessons we used ethers.js. Here we are using the
// Alchemy SDK is an umbrella library with several different packages.
//
// You can read more about the packages here:
//   https://docs.alchemy.com/reference/alchemy-sdk-api-surface-overview#api-surface
const alchemy = new Alchemy(settings);

export default function BlockExplorerPage() {
  const [blockNumber, setBlockNumber] = useState();
  const [block, setBlock] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadBlock() {
      setLoading(true);

      const number = await alchemy.core.getBlockNumber();
      setBlockNumber(number);

      const blockInfo = await alchemy.core.getBlockWithTransactions(number);
      setBlock(blockInfo);

      setLoading(false);
    }

    loadBlock();
  }, []);

  if (loading) return <p className="loading">Loading block data...</p>;

  return (
    <div className="etherscan-container">
      <h1 className="etherscan-title">Block #{blockNumber}</h1>

      {/* Bloque resumen */}
      <div className="block-card">
        <h2>Block Summary</h2>
        <div className="card-content">
          <div className="card-item">
            <strong>Block Number:</strong> {block.number}
          </div>
          <div className="card-item">
            <strong>Timestamp:</strong> {new Date(block.timestamp * 1000).toLocaleString()}
          </div>
          <div className="card-item">
            <strong>Miner:</strong> <span className="mono">{block.miner}</span>
          </div>
          <div className="card-item">
            <strong>Hash:</strong> <span className="mono">{block.hash}</span>
          </div>
          <div className="card-item">
            <strong>Parent Hash:</strong> <span className="mono">{block.parentHash}</span>
          </div>
          <div className="card-item">
            <strong>Gas Used:</strong> {block.gasUsed.toString()}
          </div>
          <div className="card-item">
            <strong>Gas Limit:</strong> {block.gasLimit.toString()}
          </div>
          <div className="card-item">
            <strong>Difficulty:</strong> <span className="mono">{block.difficulty}</span>
          </div>
          <div className="card-item">
            <strong>Transactions:</strong> {block.transactions.length}
          </div>
        </div>
      </div>

      {/* Transacciones */}
      <div className="block-card">
        <h2>Transactions</h2>
        <div className="card-content">
          {block.transactions.slice(0, 20).map((tx) => (
            <div key={tx.hash} className="tx-card">
              <div><strong>Hash:</strong> <span className="mono hash">{tx.hash}</span></div>
              <div><strong>From:</strong> <span className="mono">{tx.from}</span></div>
              <div><strong>To:</strong> <span className="mono">{tx.to || "Contract creation"}</span></div>
              <div><strong>Value:</strong> {(Number(tx.value) / 1e18).toFixed(4)} ETH</div>
              <div>
                <button
                  className="button-copy"
                  onClick={() => navigator.clipboard.writeText(tx.hash)}
                >
                  Copy Hash
                </button>
              </div>
            </div>
          ))}
        </div>

        {block.transactions.length > 20 && (
          <p className="note">
            Showing first 20 transactions of {block.transactions.length}.
          </p>
        )}
      </div>
    </div>
  );
}
